import { useState } from "react";
import API from "./api";

export default function AuthModal({ onClose, onAuthed }) {
    const [mode, setMode] = useState("login"); // "login" | "signup"
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const [busy, setBusy] = useState(false);

    const submit = async () => {
        setBusy(true);
        const fn = mode === "login" ? API.login : API.register;
        const res = await fn(username.trim(), password);
        setBusy(false);
        if (res.status === "success") {
            onAuthed(res.username);
            onClose();
        } else {
            alert(res.message || "Something went wrong");
            // helpful UX: if login failed and user doesn't exist, suggest signup
            if (mode === "login" && (res.message || "").toLowerCase().includes("invalid")) {
                const go = window.confirm("No account found or wrong password. Sign up instead?");
                if (go) setMode("signup");
            }
        }
    };

    return (
        <div style={styles.backdrop}>
            <div style={styles.modal}>
                <h3 style={{marginTop:0}}>{mode === "login" ? "Login" : "Create account"}</h3>
                <div style={{display:"flex", flexDirection:"column", gap:10}}>
                    <input
                        placeholder="Username"
                        value={username}
                        onChange={e=>setUsername(e.target.value)}
                    />
                    <input
                        placeholder="Password"
                        type="password"
                        value={password}
                        onChange={e=>setPassword(e.target.value)}
                    />
                    <button onClick={submit} disabled={busy}>
                        {busy ? "Please wait..." : (mode === "login" ? "Login" : "Sign up")}
                    </button>
                    <button onClick={onClose} style={{opacity:0.8}}>Cancel</button>
                </div>
                <div style={{marginTop:10, fontSize:13}}>
                    {mode === "login" ? (
                        <span>Don’t have an account?{" "}
                            <a href="#signup" onClick={(e)=>{e.preventDefault(); setMode("signup");}}>
                Sign up
              </a></span>
                    ) : (
                        <span>Already have an account?{" "}
                            <a href="#login" onClick={(e)=>{e.preventDefault(); setMode("login");}}>
                Log in
              </a></span>
                    )}
                </div>
            </div>
        </div>
    );
}

const styles = {
    backdrop: {
        position:"fixed", inset:0, background:"rgba(0,0,0,0.35)",
        display:"flex", alignItems:"center", justifyContent:"center", zIndex:1000
    },
    modal: {
        background:"#fff", padding:20, borderRadius:8, width:320,
        boxShadow:"0 10px 30px rgba(0,0,0,0.2)"
    }
};
